async (params, browser) => {
  // Search Booking.com
  await browser.open(`https://www.booking.com/searchresults.html?ss=${params.destination}`)

  // Wait for search results
  await browser.waitForSelector('[data-testid=\'property-card\'], .sr_property_block', 15000)

  // Let results fully render
  await browser.wait(3000)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract hotel listings
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('[data-testid="property-card"], .sr_property_block'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const nameEl = el.querySelector('[data-testid="title"], .sr-hotel__name, a[data-testid="title-link"] div'); const linkEl = el.querySelector('a[data-testid="title-link"], a.hotel_name_link, a[data-testid="property-card-desktop-single-image"]'); const priceEl = el.querySelector('[data-testid="price-and-discounted-price"], .bui-price-display__value, .prco-valign-middle-helper, span[data-testid="price-and-discounted-price"]'); const ratingEl = el.querySelector('[data-testid="review-score"] div:first-child, .bui-review-score__badge, [aria-label*="Scored"]'); const ratingTextEl = el.querySelector('[data-testid="review-score"] div:nth-child(2) div:first-child, .bui-review-score__text'); const reviewCountEl = el.querySelector('[data-testid="review-score"] div:nth-child(2) div:nth-child(2), .bui-review-score__text + div'); const locationEl = el.querySelector('[data-testid="address"], .sr_card_address_line, span[data-testid="distance"]'); const starsEl = el.querySelector('[data-testid="rating-stars"], .bui-rating, [aria-label*="stars"]'); const imgEl = el.querySelector('img[data-testid="image"], img.hotel_image, img[loading]'); const starCount = starsEl ? (starsEl.querySelectorAll('span, svg').length || starsEl.getAttribute('aria-label') || '') : ''; const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.booking.com' + linkEl.getAttribute('href')) : ''; const name = nameEl ? nameEl.textContent.trim() : ''; if (name) { results.push({ name: name, price: priceEl ? priceEl.textContent.trim() : '', rating_score: ratingEl ? ratingEl.textContent.trim() : '', rating_text: ratingTextEl ? ratingTextEl.textContent.trim() : '', review_count: reviewCountEl ? reviewCountEl.textContent.trim() : '', location: locationEl ? locationEl.textContent.trim() : '', stars: starCount, image: imgEl ? imgEl.getAttribute('src') : '', url: url }); } } return { destination: params.destination, result_count: results.length, results: results }`)

  return search_results
}
